// --- types.d.ts ---
// Path: /virtual/types.d.ts

export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed in km/h or mph */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastDay[];
}

export interface WeatherHeroProps {
  city: string;
  temperature: number;
  condition: string;
  unit: string;
}

export interface WeatherMetricsProps {
  humidity: number;
  windSpeed: number;
}

export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit: string;
}

export interface ForecastItemProps {
  day: string;
  icon: string;
  high: number;
  low: number;
  unit: string;
}

export interface UseWeatherReturn {
  formattedTemp: string;
  formattedWind: string;
  formattedHumidity: string;
  displayUnit: string;
  conditionIcon: string;
}

// --- constants.ts ---
// Path: /virtual/constants.ts
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const WEATHER_ICONS = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Snowy: '❄️',
  Thunderstorm: '⛈️',
  'Partly Cloudy': '⛅',
  Windy: '💨',
  Mist: '🌫️',
  Default: '🌡️',
} as const;

export const UNIT_LABELS = {
  TEMP_C: '°C',
  TEMP_F: '°F',
  WIND_KMH: 'km/h',
  WIND_MPH: 'mph',
  HUMIDITY: '%',
} as const;

export const DEFAULT_WEATHER_UNIT = 'C' as const;

// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {

  const displayUnit = useMemo(() => `°${props.unit || 'C'}`, [props.unit]);

  const formattedTemp = useMemo(() => `${props.temperature}${displayUnit}`, [props.temperature, displayUnit]);

  const formattedWind = useMemo(() => `${props.windSpeed} km/h`, [props.windSpeed]);

  const formattedHumidity = useMemo(() => `${props.humidity}%`, [props.humidity]);

  const conditionIcon = useMemo(() => {
    const normalizedCondition = (props.condition || '').toLowerCase();
    switch (normalizedCondition) {
      case 'sunny':
        return '☀️';
      case 'cloudy':
        return '☁️';
      case 'rainy':
        return '🌧️';
      case 'snowy':
        return '❄️';
      case 'partly cloudy':
        return '⛅';
      case 'thunderstorm':
        return '⛈️';
      default:
        return '☁️';
    }
  }, [props.condition]);

  return {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    displayUnit,
    conditionIcon,
  };
}


