import React from 'react';
import { Stack, Text, Icon, Divider, Box } from '@ggui-ai/design/primitives';
import { WeatherMetricsProps } from '/virtual/types';

/**
 * WeatherMetrics component displays secondary weather data like humidity and wind speed.
 * It features a centered horizontal layout with icons and descriptive labels.
 */
export const WeatherMetrics: React.FC<WeatherMetricsProps> = ({
  humidity,
  windSpeed,
}) => {
  return (
    <Stack gap={0} style={{ width: '100%' }}>
      {/* Subtle divider to separate metrics from the hero section */}
      <Divider margin={0} />

      <Box padding="var(--ggui-spacing-4, 16px)">
        <Stack
          direction="horizontal"
          justify="center"
          align="center"
          gap="var(--ggui-spacing-6, 24px)"
        >
          {/* Humidity Block */}
          <Stack align="center" gap="var(--ggui-spacing-1, 4px)">
            <Icon
              name="humidity"
              size={24}
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            />
            <Text
              variant="bodyLarge"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
          </Stack>

          {/* Wind Speed Block */}
          <Stack align="center" gap="var(--ggui-spacing-1, 4px)">
            <Icon name="wind" size={24} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
            <Text
              variant="bodyLarge"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} km/h
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind
            </Text>
          </Stack>
        </Stack>
      </Box>
    </Stack>
  );
};

