import React from 'react';
import { Stack, Text, Box } from '@ggui-ai/design/primitives';
import { ForecastItemProps } from '/virtual/types';

/**
 * Maps weather condition strings to emojis for visual representation.
 */
const iconMap: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  snowy: '❄️',
  'partly-cloudy': '⛅',
};

/**
 * ForecastItem displays a summary of weather for a single day.
 */
export const ForecastItem: React.FC<ForecastItemProps> = ({
  day,
  icon,
  high,
  low,
  unit,
}) => {
  const displayIcon = iconMap[icon.toLowerCase()] || '☀️';

  return (
    <Stack
      align="center"
      justify="center"
      gap="var(--ggui-spacing-2, 8px)"
    >
      <Text
        variant="overline"
        color="var(--ggui-color-onSurfaceVariant)"
        align="center"
      >
        {day}
      </Text>

      <Box paddingY={4}>
        <Text size="2xl" align="center">
          {displayIcon}
        </Text>
      </Box>

      <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
        <Text variant="bodySmall" weight="bold">
          {high}°{unit}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {low}°{unit}
        </Text>
      </Stack>
    </Stack>
  );
};

export default ForecastItem;

