// Path: /virtual/components/ForecastStrip.tsx
import React from 'react';
import { Stack, Box, Divider, Text } from '@ggui-ai/design/primitives';
import { ForecastStripProps, ForecastItemProps } from '/virtual/types';

/**
 * ForecastItem renders an individual day's weather summary.
 * Internal helper component used by ForecastStrip.
 */
const ForecastItem = ({ day, icon, high, low, unit }: ForecastItemProps) => {
  return (
    <Stack align="center" gap={8}>
      <Text 
        variant="label" 
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
      >
        {day}
      </Text>

      {/* Weather icons are typically passed as emojis or status strings.
          Using Text with XL size to render them prominently. */}
      <Text size="xl">
        {icon}
      </Text>

      <Stack direction="horizontal" gap={4} align="center">
        <Text variant="bodySmall" weight="bold">
          {high}°
        </Text>
        <Text 
          variant="bodySmall" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          / {low}°{unit}
        </Text>
      </Stack>
    </Stack>
  );
};

/**
 * ForecastStrip displays the 5-day forecast at the bottom of the weather card.
 */
export const ForecastStrip = ({ forecast, unit }: ForecastStripProps) => {
  return (
    <Box padding="var(--ggui-spacing-4, 16px) 0 0 0">
      <Divider margin={16} />

      {/* Scrollable container for responsive layout on smaller screens */}
      <Box paddingX={16} style={{ overflowX: 'auto', WebkitOverflowScrolling: 'touch' } as any}>
        <Stack 
          direction="horizontal" 
          justify="between" 
          align="center" 
          gap={16}
        >
          {forecast.map((item, index) => (
            <ForecastItem
              key={`${item.day}-${index}`}
              day={item.day}
              icon={item.icon}
              high={item.high}
              low={item.low}
              unit={unit}
            />
          ))}
        </Stack>
      </Box>
    </Box>
  );
};

