import type { Props, HookReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Divider } from '@ggui-ai/design/primitives';

export function MainView(props: Props & HookReturn) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Container maxWidth="450px" center padding="var(--ggui-spacing-8)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        radius="xl"
        border={true}
        style={{
          backgroundColor: 'var(--ggui-color-surfaceVariant)',
          maxWidth: '450px',
          width: '100%',
        }}
      >
        <Stack gap="var(--ggui-spacing-4)" direction="vertical" align="stretch">
          <WeatherHero city={city} temperature={temperature} condition={condition} unit={unit} />

          <Divider margin="var(--ggui-spacing-2)" />

          <WeatherMetrics humidity={humidity} windSpeed={windSpeed} />

          <Divider margin="var(--ggui-spacing-2)" />

          <ForecastStrip forecast={forecast} unit={unit} />
        </Stack>
      </Card>
    </Container>
  );
}


